	@echo "Building httos release"
	@cmake -S . -B build-riscv -DCMAKE_BUILD_TYPE=Release -DCMAKE_EXPORT_COMPILE_COMMANDS=ON -DRISCV=ON -DLOONGARCH=OFF
	@cmake --build build-riscv --target build  -- -j 8
	@echo "Done"

