	@echo "Building httos release"
	@cmake -S . -B build-loongarch -DCMAKE_BUILD_TYPE=Release -DCMAKE_EXPORT_COMPILE_COMMANDS=ON -DRISCV=OFF -DLOONGARCH=ON
	@cmake --build build-loongarch --target build  -- -j 8
