clean:
	@echo "Cleaning httos"
	@if [ -d "build" ]; then rm -r build; fi
	@if [ -d "build-riscv" ]; then rm -r build-riscv; fi
	@if [ -d "build-loongarch" ]; then rm -r build-loongarch; fi
	@if [ -d "bin" ]; then rm -r bin; fi
	@if [ -d "image" ]; then rm -r image; fi
	@echo "Done"


make-image:
	$(call build_image,fs)

make-image-force:
	@rm -f image/fs.img
	$(call build_image,fs)

all: build-release-riscv make-image-force
	@cp bin/kernel-riscv kernel-rv
	@cp image/fs.img disk.img
	@${MAKE} clean
	@${MAKE} build-release-loongarch
	@cp bin/kernel-loongarch kernel-la
	@cp disk.img disk-la.img


define build_image
	@mkdir -p image
	@mkdir -p data
	@mkdir -p data/mnt
	@mkdir -p data/root-lib
	@mkdir -p data/root-lib64
	@if [ ! -f "image/$(1).img" ] || [ "$(1)" = "tests" ] || [ "x$(1)" = "xbusybox" ] || [ "x$(1)" = "xfinal" ] ; then\
		rm -rf data/root-lib/* data/root-lib64/* ;\
		if [ -f basic/sdcard-rv.img ]; then \
			debugfs -R 'dump /glibc/lib/ld-linux-riscv64-lp64d.so.1 data/root-lib/ld-linux-riscv64-lp64d.so.1' basic/sdcard-rv.img >/dev/null 2>&1 || true ;\
			debugfs -R 'dump /glibc/lib/libc.so data/root-lib/libc.so.6' basic/sdcard-rv.img >/dev/null 2>&1 || true ;\
			debugfs -R 'dump /glibc/lib/libm.so data/root-lib/libm.so.6' basic/sdcard-rv.img >/dev/null 2>&1 || true ;\
			debugfs -R 'dump /musl/lib/libc.so data/root-lib/libc.so' basic/sdcard-rv.img >/dev/null 2>&1 || true ;\
			if [ -f data/root-lib/libc.so ]; then cp data/root-lib/libc.so data/root-lib/ld-musl-riscv64-sf.so.1 ; fi ;\
		fi ;\
		if [ -f basic/sdcard-la.img ]; then \
			debugfs -R 'dump /glibc/lib/ld-linux-loongarch-lp64d.so.1 data/root-lib64/ld-linux-loongarch-lp64d.so.1' basic/sdcard-la.img >/dev/null 2>&1 || true ;\
			debugfs -R 'dump /glibc/lib/libc.so.6 data/root-lib64/libc.so.6' basic/sdcard-la.img >/dev/null 2>&1 || true ;\
			debugfs -R 'dump /glibc/lib/libm.so.6 data/root-lib64/libm.so.6' basic/sdcard-la.img >/dev/null 2>&1 || true ;\
			debugfs -R 'dump /musl/lib/libc.so data/root-lib64/libc.so' basic/sdcard-la.img >/dev/null 2>&1 || true ;\
			if [ -f data/root-lib64/libc.so ]; then cp data/root-lib64/libc.so data/root-lib64/ld-musl-loongarch-lp64d.so.1 ; fi ;\
		fi ;\
		dd if=/dev/zero of=$(1).img bs=1M count=512 ;\
		mkfs.ext4 -O ^metadata_csum -F -b 4096 -L rootfs $(1).img ;\
		find user/bin -mindepth 1 -type d | sed 's#^user/bin##' | while read d ; do \
			debugfs -w -R "mkdir $$d" $(1).img >/dev/null 2>&1 || true ;\
		done ;\
		find user/bin -mindepth 1 -type f | sed 's#^user/bin/##' | while read f ; do \
			debugfs -w -R "write user/bin/$$f /$$f" $(1).img >/dev/null 2>&1 || exit 1 ;\
		done ;\
		debugfs -w -R 'mkdir /lib' $(1).img >/dev/null 2>&1 || exit 1 ;\
		for f in data/root-lib/* ; do \
			[ -f "$$f" ] || continue ;\
			debugfs -w -R "write $$f /lib/$$(basename $$f)" $(1).img >/dev/null 2>&1 || exit 1 ;\
		done ;\
		debugfs -w -R 'mkdir /lib64' $(1).img >/dev/null 2>&1 || exit 1 ;\
		for f in data/root-lib64/* ; do \
			[ -f "$$f" ] || continue ;\
			debugfs -w -R "write $$f /lib64/$$(basename $$f)" $(1).img >/dev/null 2>&1 || exit 1 ;\
		done ;\
		md5sum $(1).img ;\
		mv $(1).img image/;\
	fi
endef

